commands.examples:
CREATE INDEX idx_users_email ON users (email);
CREATE UNIQUE INDEX idx_users_username ON users (username);
CREATE INDEX CONCURRENTLY idx_orders_date ON orders (created_at);

-- Partial index
CREATE INDEX idx_active_users ON users (email) WHERE active = true;

-- Expression index
CREATE INDEX idx_users_lower_email ON users (LOWER(email));

-- Multi-column index
CREATE INDEX idx_orders_user_date ON orders (user_id, created_at DESC);

-- GIN untuk JSONB
CREATE INDEX idx_data_gin ON configs USING GIN (data);

EXPLAIN SELECT * FROM users WHERE email = 'test@mail.com';

EXPLAIN ANALYZE SELECT * FROM orders WHERE user_id = 5;

EXPLAIN (ANALYZE, BUFFERS, FORMAT json)
SELECT u.name, COUNT(o.id)
FROM users u JOIN orders o ON u.id = o.user_id
GROUP BY u.name;

REINDEX INDEX idx_users_email;
REINDEX TABLE users;
REINDEX CONCURRENTLY TABLE orders;
